const Comic = () => {
    return (
        <div className="container bg-dark p-5">
            <h2 className="text-warning text-center">TẠO TRUYỆN TRANH MỚI</h2>
            <form className="container">
                <label>Tên truyện: </label>
                <input type="text"/>
            </form>
        </div>
    )
}
export default Comic;
